// Valida input y construye params para dataLayers:get.
// Input: { lat, lon, radiusMeters? }
const src = $input.first().json;
const body = src.body || src;
const lat = body.lat != null ? Number(body.lat) : null;
const lon = body.lon != null ? Number(body.lon) : null;
if (lat == null || lon == null || !Number.isFinite(lat) || !Number.isFinite(lon)) {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'lat y lon requeridos' } }];
}
const radiusMeters = body.radiusMeters != null ? Math.min(100, Math.max(10, Number(body.radiusMeters))) : 50;
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GKEY = safeEnv('GOOGLE_API_KEY');
if (!GKEY) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no configurada' } }];
}
return [{ json: { lat, lon, radiusMeters, gkey: GKEY } }];

// Chequea si el nodo anterior devolvió error (ok:false).
const d = $input.first().json;
return [{ json: { isError: d.ok === false, ...d } }];

// Extrae URLs firmadas + bounds del response de dataLayers:get.
// Google Solar devuelve boundingBox.low/high (no sw/ne).
// bounds es opcional: si falta, el frontend los extrae del GeoTIFF.
const d = $input.first().json;
if (!d || d.error) {
  const msg = d?.error?.message || 'dataLayers API error';
  return [{ json: { ok: false, reason: 'api_error', detail: msg } }];
}
let bounds = null;
const bb = d.boundingBox;
if (bb) {
  const lo = bb.low || bb.sw || bb.southWest;
  const hi = bb.high || bb.ne || bb.northEast;
  if (lo && hi) {
    bounds = {
      sw: { lat: Number(lo.latitude ?? lo.lat), lng: Number(lo.longitude ?? lo.lng) },
      ne: { lat: Number(hi.latitude ?? hi.lat), lng: Number(hi.longitude ?? hi.lng) },
    };
  }
}
return [{ json: {
  ok: true,
  annualFluxUrl: d.annualFluxUrl || null,
  dsmUrl: d.dsmUrl || null,
  maskUrl: d.maskUrl || null,
  imageryUrl: d.imageryUrl || null,
  monthlyFluxUrls: Array.isArray(d.monthlyFluxUrl) ? d.monthlyFluxUrl : [],
  bounds,
  imageryDate: d.imageryDate || null,
  imageryProcessedDate: d.imageryProcessedDate || null,
} }];
